// ==UserScript==
// @name         Restore Hastings Bin Calendar
// @namespace    https://github.com/AV1917
// @homepage     https://github.com/AV1917
// @version      1.0.2
// @description  A userscript that recreates the PDF download for the selected bin collection schedule and puts it back where it belongs on the Hastings Borough Council webpage.
// @icon         https://github.com/AV1917/restore-hastings-bin-calendar/raw/main/docs/RHBC.png
// @author       AV1917
// @match        https://www.hastings.gov.uk/waste_recycling/lookup/*
// @require      https://cdn.jsdelivr.net/npm/jspdf@2.5.1/dist/jspdf.umd.min.js
// @downloadURL  https://github.com/AV1917/restore-hastings-bin-calendar/raw/main/restore-hastings-bin-calendar.user.js
// @updateURL    https://github.com/AV1917/restore-hastings-bin-calendar/raw/main/restore-hastings-bin-calendar.user.js
// @grant        none
// @run-at       document-end
// ==/UserScript==

(function () {
  "use strict";

  const LOOKUP_ENDPOINT = "/MyArea/CollectionDays.asmx/LookupCollectionDaysByService";
  const CALENDAR_BASE = "/waste_recycling/calendars2024/";
  const BIN_IMAGE_BASE = "https://fs-filestore-eu.s3.amazonaws.com/hastings/live/self/images/bins/";
  const DATE_RE = /(Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday)\s+\d{1,2}\s+[A-Za-z]+\s+\d{4}/g;
  const MONTHS = {
    january: 0,
    february: 1,
    march: 2,
    april: 3,
    may: 4,
    june: 5,
    july: 6,
    august: 7,
    september: 8,
    october: 9,
    november: 10,
    december: 11
  };
  const HOLLY_DATA_URL = "data:image/png;base64,";

  const XMAS_COLLECTIONS_PATH = "/waste_recycling/xmas-waste/xmas-collections/";

  const state = {
    lookup: null,
    calendarCache: new Map(),
    gardenSuspensionRule: undefined
  };

  patchXHR();

  function patchXHR() {
    const proto = XMLHttpRequest.prototype;
    if (proto.__hbcPatched) return;
    proto.__hbcPatched = true;
    const open = proto.open;
    const send = proto.send;
    proto.open = function (method, url) {
      this.__hbcUrl = String(url || "");
      return open.apply(this, arguments);
    };
    proto.send = function () {
      const url = String(this.__hbcUrl || "").toLowerCase();
      if (url.includes(LOOKUP_ENDPOINT.toLowerCase())) {
        this.addEventListener("load", () => {
          const payload = JSON.parse(this.responseText);
          const lookup = normaliseLookup(payload);
          state.lookup = lookup;
          upsertButton();
        });
      }
      return send.apply(this, arguments);
    };
  }

  function normaliseLookup(payload) {
    const rows = Array.isArray(payload?.d) ? payload.d : null;
    if (!rows || !rows.length) throw new Error("No services.");
    const services = rows.map((r) => {
      const service = String(r?.Service || "").trim();
      const kind = classifyServiceKind(service);
      if (!kind) return null;
      return {
        kind,
        service,
        schedule: String(r?.Schedule ?? "").trim(),
        image: String(r?.Image ?? "").trim(),
        dates: normaliseDateItems(r?.Dates)
      };
    }).filter(Boolean);
    const recycling = services.find((s) => s.kind === "recycling") || null;
    const rubbish = services.find((s) => s.kind === "rubbish") || null;
    if (!recycling || !rubbish) throw new Error("Missing core services.");
    const garden = services.find((s) => s.kind === "garden") || null;
    const food = services.find((s) => s.kind === "food") || null;
    const scheduleCode = composeScheduleCode(recycling, rubbish);
    return { services, recycling, rubbish, garden, food, scheduleCode };
  }

  function classifyServiceKind(serviceName) {
    const lower = serviceName.toLowerCase();
    if (lower.includes("garden")) return "garden";
    if (lower.includes("food")) return "food";
    if (lower.includes("recycling")) return "recycling";
    if (lower.includes("rubbish")) return "rubbish";
    return null;
  }

  function composeScheduleCode(recycling, rubbish) {
    const rec = String(recycling?.schedule || "").trim();
    const ref = String(rubbish?.schedule || "").trim();
    if (!rec || !ref) throw new Error("Missing schedule code.");
    if (/^rec/i.test(rec) && /^ref/i.test(ref)) return rec + ref;
    if (/^ref/i.test(rec) && /^rec/i.test(ref)) return ref + rec;
    throw new Error("Unsupported schedule pair.");
  }

  function upsertButton() {
    if (!state.lookup?.scheduleCode) return;
    const host =
      document.querySelector("#divCalendar") ||
      document.querySelector("#divResults") ||
      document.querySelector("#ctl00_leftCol_PageBody") ||
      document.body;
    if (!host) return;

    let wrap = document.getElementById("hbcPdfDownloadWrap");
    if (!wrap) {
      wrap = document.createElement("div");
      wrap.id = "hbcPdfDownloadWrap";
      wrap.style.margin = "0.6em 0 1em";
      const iconP = document.createElement("p");
      iconP.style.display = "inline-block";
      iconP.style.verticalAlign = "bottom";
      iconP.style.margin = "0 0.2em 0 0";
      const icon = document.createElement("img");
      icon.src = "https://www.hastings.gov.uk/static/images/calendar.png";
      icon.title = "calendar icon";
      icon.alt = "calendar icon";
      iconP.appendChild(icon);
      const linkP = document.createElement("p");
      linkP.style.display = "inline-block";
      linkP.style.verticalAlign = "bottom";
      linkP.style.margin = "0.2em 0.4em";
      const link = document.createElement("a");
      link.id = "hbcPdfDownloadLink";
      link.href = "#";
      link.textContent = "Download your full collection calendar as a PDF";
      link.addEventListener("click", onDownloadClick);
      linkP.appendChild(link);
      wrap.appendChild(iconP);
      wrap.appendChild(linkP);
    }
    if (!wrap.isConnected) host.appendChild(wrap);
  }

  async function onDownloadClick(event) {
    event.preventDefault();
    const link = event.currentTarget;
    if (link.dataset.busy === "1") return;
    link.dataset.busy = "1";
    const oldText = link.textContent;
    link.textContent = "generating PDF...";
    try {
      const lookup = state.lookup;
      if (!lookup?.scheduleCode) throw new Error("Lookup results not ready.");
      const cal = await fetchCalendarData(lookup.scheduleCode);
      const months = normaliseMonths(cal.grouped, cal.isWeekly, cal.year);
      const gardenSeed = mergeServiceDateItems(
        lookup.garden?.dates || [],
        collectServiceItems(months, "garden")
      );
      const foodLookupSeed = normaliseDateItems(lookup.food?.dates || []);
      const foodSeed = mergeServiceDateItems(
        foodLookupSeed,
        collectServiceItems(months, "food")
      );
      attachGarden(months, estimateGardenDates(gardenSeed, cal.year, cal.isWeekly));
      const gardenRule = await getGardenSuspensionRule();
      attachFood(months, estimateFoodDates(foodSeed, cal.year, foodLookupSeed, gardenRule));
      await markCancelledGardenCollections(months, gardenRule);
      pruneEmptyLeadMonth(months, cal.isWeekly);
      const icons = await loadIcons(lookup);
      const jsPDFCtor = await getJsPdfCtor();
      const hasGarden = months.some((m) => Array.isArray(m.garden) && m.garden.length > 0);
      const hasFood = months.some((m) => Array.isArray(m.food) && m.food.length > 0);
      const doc = buildPdf(jsPDFCtor, {
        title: cal.title,
        year: cal.year,
        isWeekly: cal.isWeekly,
        scheduleCode: lookup.scheduleCode,
        months,
        icons,
        hasGarden,
        hasFood
      });
      doc.save(lookup.scheduleCode + "-" + cal.year + ".pdf");
    } catch (error) {
      console.error("[HBC PDF] generation failed:", error);
      alert("Could not generate the PDF. Please run lookup again and retry.");
    } finally {
      link.dataset.busy = "0";
      link.textContent = oldText;
    }
  }

  async function fetchCalendarData(scheduleCode) {
    if (state.calendarCache.has(scheduleCode)) return state.calendarCache.get(scheduleCode);
    const url = new URL(CALENDAR_BASE + scheduleCode + "/", location.origin).toString();
    const res = await fetch(url, { credentials: "include", cache: "no-cache" });
    if (!res.ok) throw new Error("Failed to load calendar page.");
    const html = await res.text();
    const doc = new DOMParser().parseFromString(html, "text/html");
    const pageBody = doc.querySelector("#PageBody");
    if (!pageBody) throw new Error("Calendar page has no #PageBody.");
    const title = (doc.querySelector(".leftCol.contCol > h1")?.textContent || "Collection calendar").trim();
    const isWeekly = /weekly/i.test(title) || !/fort\d/i.test(scheduleCode);
    const year = getCalendarYear(pageBody);
    const grouped = parseCalendarPage(pageBody, isWeekly);
    if (!grouped.length) throw new Error("No calendar dates found.");
    const data = { title, isWeekly, year, grouped };
    state.calendarCache.set(scheduleCode, data);
    return data;
  }

  function getCalendarYear(pageBody) {
    const m = (pageBody.textContent || "").match(/collection days for\s+(\d{4})/i);
    const year = m ? Number(m[1]) : NaN;
    if (!Number.isFinite(year)) {
      throw new Error("Calendar year not found in page content.");
    }
    return year;
  }

  function parseCalendarPage(pageBody, isWeekly) {
    const rows = Array.from(pageBody.children).filter(
      (n) => n.tagName === "P" && n.querySelector("img")
    );
    const entries = [];
    for (const row of rows) {
      const dates = (row.textContent || "").match(DATE_RE) || [];
      if (!dates.length) continue;
      const strong = new Set(
        Array.from(row.querySelectorAll("strong"))
          .flatMap((n) => ((n.textContent || "").match(DATE_RE) || []))
          .map(norm)
      );
      const type = inferType(row, isWeekly);
      for (const raw of dates) {
        const p = parseDate(norm(raw));
        if (!p) {
          throw new Error('Could not parse calendar date "' + norm(raw) + '".');
        }
        entries.push({ type, date: p, bold: strong.has(norm(raw)) });
      }
    }
    return isWeekly ? groupWeekly(entries) : groupFortnightly(entries);
  }

  function inferType(row, isWeekly) {
    const img = row.querySelector("img");
    const rowText = row.textContent || "";
    const text = (
      ((img && img.getAttribute("src")) || "") +
      " " +
      ((img && img.getAttribute("alt")) || "") +
      " " +
      ((img && img.getAttribute("title")) || "") +
      " " +
      ((row.previousElementSibling && row.previousElementSibling.textContent) || "") +
      " " +
      rowText
    ).toLowerCase();
    if (text.includes("garden") || text.includes("gw-")) return "garden";
    if (text.includes("food") || text.includes("fw-") || text.includes("caddy")) return "food";
    if (isWeekly) return "both";
    if (text.includes("dr-sack") || text.includes("recycling")) return "recycling";
    if (text.includes("dw-sack") || text.includes("rubbish")) return "rubbish";
    throw new Error('Could not infer fortnightly collection type from row text: "' + text.slice(0, 160) + '".');
  }

  function groupWeekly(entries) {
    const map = new Map();
    for (const e of entries) {
      const k = monthKey(e.date);
      if (!map.has(k)) {
        map.set(k, {
          start: new Date(e.date.getFullYear(), e.date.getMonth(), 1),
          label: monthLabel(e.date),
          dates: [],
          garden: [],
          food: []
        });
      }
      const item = { date: e.date, bold: !!e.bold, estimated: false };
      if (e.type === "garden") map.get(k).garden.push(item);
      else if (e.type === "food") map.get(k).food.push(item);
      else map.get(k).dates.push(item);
    }
    return Array.from(map.values())
      .map((m) => ({
        start: m.start,
        label: m.label,
        dates: dedupeSortItems(m.dates),
        garden: dedupeSortItems(m.garden),
        food: dedupeSortItems(m.food)
      }))
      .sort((a, b) => a.start - b.start);
  }

  function groupFortnightly(entries) {
    const map = new Map();
    for (const e of entries) {
      const k = monthKey(e.date);
      if (!map.has(k)) {
        map.set(k, {
          start: new Date(e.date.getFullYear(), e.date.getMonth(), 1),
          label: monthLabel(e.date),
          recycling: [],
          rubbish: [],
          garden: [],
          food: []
        });
      }
      const item = { date: e.date, bold: !!e.bold, estimated: false };
      if (e.type === "recycling") map.get(k).recycling.push(item);
      else if (e.type === "rubbish") map.get(k).rubbish.push(item);
      else if (e.type === "garden") map.get(k).garden.push(item);
      else if (e.type === "food") map.get(k).food.push(item);
      else continue;
    }
    return Array.from(map.values()).map((m) => ({
      start: m.start,
      label: m.label,
      recycling: dedupeSortItems(m.recycling),
      rubbish: dedupeSortItems(m.rubbish),
      garden: dedupeSortItems(m.garden),
      food: dedupeSortItems(m.food)
    })).sort((a, b) => a.start - b.start);
  }

  function normaliseMonths(grouped, isWeekly, year) {
    const byMonth = new Map(grouped.map((m) => [monthKey(m.start), m]));
    const out = [];

    const leadKey = monthKey(new Date(year - 1, 11, 1));
    const lead = byMonth.get(leadKey);
    if (isWeekly) {
      out.push({
        idx: 11,
        year: year - 1,
        label: monthName(11) + " " + (year - 1),
        dates: lead ? (lead.dates || []) : [],
        garden: lead ? (lead.garden || []) : [],
        food: lead ? (lead.food || []) : []
      });
    } else {
      out.push({
        idx: 11,
        year: year - 1,
        label: monthName(11) + " " + (year - 1),
        recycling: lead ? (lead.recycling || []) : [],
        rubbish: lead ? (lead.rubbish || []) : [],
        garden: lead ? (lead.garden || []) : [],
        food: lead ? (lead.food || []) : []
      });
    }

    for (let i = 0; i < 12; i++) {
      const src = byMonth.get(monthKey(new Date(year, i, 1)));
      if (isWeekly) {
        out.push({
          idx: i,
          year,
          label: monthName(i) + " " + year,
          dates: src ? src.dates : [],
          garden: src ? src.garden : [],
          food: src ? src.food : []
        });
      } else {
        out.push({
          idx: i,
          year,
          label: monthName(i) + " " + year,
          recycling: src ? src.recycling : [],
          rubbish: src ? src.rubbish : [],
          garden: src ? src.garden : [],
          food: src ? src.food : []
        });
      }
    }
    return out;
  }

  function estimateGardenDates(seed, year, isWeekly) {
    const range = calendarDisplayRange(year);
    return estimateRecurringDates(
      normaliseDateItems(seed),
      range.start,
      range.end,
      isWeekly ? 7 : 14
    );
  }

  function estimateFoodDates(seed, year, lateYearSeed, gardenRule) {
    const allItems = normaliseDateItems(seed);
    const lateYearItems = normaliseDateItems(lateYearSeed === undefined ? seed : lateYearSeed);
    const range = calendarDisplayRange(year);
    const lateYearSeedCutoff = new Date(year, 11, 25);
    const allowLateYearExtrapolation = lateYearItems.some(
      (x) => x.date.getFullYear() === year && x.date >= lateYearSeedCutoff
    );
    return estimateRecurringDates(
      allItems,
      range.start,
      range.end,
      7,
      (date) => shouldExtrapolateFoodDate(date, year, lateYearSeedCutoff, allowLateYearExtrapolation, gardenRule)
    );
  }

  function shouldExtrapolateFoodDate(date, calendarYear, lateYearSeedCutoff, allowLateYearExtrapolation, gardenRule) {
    if (date.getFullYear() === calendarYear) {
      return allowLateYearExtrapolation || date < lateYearSeedCutoff;
    }
    if (date.getFullYear() === calendarYear - 1) {
      return !isDateWithinGardenSuspensionWindow(date, calendarYear - 1, gardenRule);
    }
    return true;
  }

  function calendarDisplayRange(year) {
    return {
      start: new Date(year - 1, 11, 1),
      end: new Date(year, 11, 31)
    };
  }

  function estimateRecurringDates(seed, start, end, fallbackInterval, includeEstimate) {
    const allItems = normaliseDateItems(seed);
    if (!allItems.length) return [];
    const informative = allItems.filter((x) => !x.bold);
    if (!informative.length) return cloneItemsInRange(allItems, start, end);
    const interval = inferInterval(
      informative.map((x) => x.date),
      fallbackInterval
    );
    let cur = new Date(informative[0].date);
    while (cur > start) cur.setDate(cur.getDate() - interval);
    while (cur < start) cur.setDate(cur.getDate() + interval);
    const estimated = [];
    while (cur <= end) {
      const candidate = new Date(cur);
      if (!includeEstimate || includeEstimate(candidate)) {
        estimated.push({ date: candidate, bold: false, estimated: true });
      }
      cur.setDate(cur.getDate() + interval);
    }
    return mergeActualWithEstimated(estimated, allItems, start, end);
  }

  function cloneItemsInRange(items, start, end) {
    return normaliseDateItems(items)
      .filter((item) => item.date >= start && item.date <= end)
      .map((item) => ({ date: new Date(item.date), bold: !!item.bold, estimated: false }));
  }

  function mergeActualWithEstimated(estimated, actual, start, end) {
    const out = new Map();
    for (const item of estimated || []) {
      out.set(item.date.getTime(), {
        date: new Date(item.date),
        bold: !!item.bold,
        estimated: !!item.estimated
      });
    }
    for (const item of normaliseDateItems(actual)) {
      if (item.date < start || item.date > end) continue;
      const key = item.date.getTime();
      const existing = out.get(key);
      if (existing) {
        existing.bold = existing.bold || !!item.bold;
        existing.estimated = false;
      } else {
        out.set(key, {
          date: new Date(item.date),
          bold: !!item.bold,
          estimated: false
        });
      }
    }
    return Array.from(out.values()).sort((a, b) => a.date - b.date);
  }

  function inferInterval(sorted, fallback) {
    if (sorted.length < 2) return fallback;
    const diffs = [];
    for (let i = 1; i < sorted.length; i++) {
      const d = Math.round((sorted[i] - sorted[i - 1]) / 86400000);
      if (d > 0) diffs.push(d);
    }
    if (!diffs.length) return fallback;
    diffs.sort((a, b) => a - b);
    const med = diffs[Math.floor(diffs.length / 2)];
    if (med >= 6 && med <= 8) return 7;
    if (med >= 12 && med <= 16) return 14;
    return Math.max(1, med);
  }

  function attachGarden(months, garden) {
    if (!garden.length) return;
    for (const m of months) m.garden = [];
    const monthMap = new Map(months.map((m) => [monthKey(new Date(m.year, m.idx, 1)), m]));
    for (const g of garden) {
      const m = monthMap.get(monthKey(g.date));
      if (m) m.garden.push(g);
    }
    for (const m of months) m.garden = dedupeSortItems(m.garden || []);
  }

  function attachFood(months, food) {
    if (!food.length) return;
    for (const m of months) m.food = [];
    const monthMap = new Map(months.map((m) => [monthKey(new Date(m.year, m.idx, 1)), m]));
    for (const f of food) {
      const m = monthMap.get(monthKey(f.date));
      if (m) m.food.push(f);
    }
    for (const m of months) m.food = dedupeSortItems(m.food || []);
  }

  function collectServiceItems(months, key) {
    if (!Array.isArray(months)) return [];
    return months.flatMap((month) => Array.isArray(month?.[key]) ? month[key] : []);
  }

  function mergeServiceDateItems() {
    const merged = [];
    for (const values of arguments) {
      merged.push(...normaliseDateItems(values));
    }
    return dedupeSortItems(merged);
  }

  function pruneEmptyLeadMonth(months, isWeekly) {
    if (!Array.isArray(months) || !months.length) return;
    const lead = months[0];
    if (!lead || lead.year !== months[1]?.year - 1 || lead.idx !== 11) return;
    const hasCore = isWeekly
      ? Array.isArray(lead.dates) && lead.dates.length > 0
      : (Array.isArray(lead.recycling) && lead.recycling.length > 0) ||
        (Array.isArray(lead.rubbish) && lead.rubbish.length > 0);
    const hasExtras =
      (Array.isArray(lead.garden) && lead.garden.length > 0) ||
      (Array.isArray(lead.food) && lead.food.length > 0);
    if (!hasCore && !hasExtras) months.shift();
  }

  async function markCancelledGardenCollections(months, rule) {
    const hasGarden = Array.isArray(months) && months.some((m) => Array.isArray(m.garden) && m.garden.length > 0);
    if (!hasGarden) return;
    if (rule === undefined) rule = await getGardenSuspensionRule();
    const windows = buildGardenCancellationWindows(months, rule);
    if (!windows.length) return;
    for (const month of months) {
      const nextGarden = [];
      for (const item of month.garden || []) {
        item.cancelled = false;
        const window = windows.find((w) => item.date >= w.start && item.date < w.resume);
        if (!window) {
          nextGarden.push(item);
          continue;
        }
        if (window.mode === "omit") continue;
        item.cancelled = true;
        nextGarden.push(item);
      }
      month.garden = nextGarden;
    }
  }

  function buildGardenCancellationWindows(months, rule) {
    const gardenDates = (Array.isArray(months) ? months : [])
      .flatMap((m) => Array.isArray(m?.garden) ? m.garden : [])
      .map((item) => item?.date)
      .filter((date) => date instanceof Date && Number.isFinite(date.getTime()));
    if (!gardenDates.length) return [];
    const minDate = new Date(Math.min(...gardenDates.map((date) => date.getTime())));
    const maxDate = new Date(Math.max(...gardenDates.map((date) => date.getTime())));
    const minYear = minDate.getFullYear();
    const maxYear = maxDate.getFullYear();
    const startOffsetDays = Number.isFinite(rule?.startOffsetDays) ? Number(rule.startOffsetDays) : 0;
    const durationDays = Number.isFinite(rule?.durationDays) && rule.durationDays > 0 ? Number(rule.durationDays) : 14;
    const sourceChristmasYear = Number.isInteger(rule?.sourceChristmasYear) ? Number(rule.sourceChristmasYear) : null;
    const out = [];
    for (let christmasYear = minYear - 1; christmasYear <= maxYear; christmasYear++) {
      const christmas = new Date(christmasYear, 11, 25);
      const start = addDays(christmas, startOffsetDays);
      const resume = addDays(start, durationDays);
      if (resume <= minDate || start > maxDate) continue;
      out.push({
        start,
        resume,
        mode: sourceChristmasYear !== null && christmasYear > sourceChristmasYear ? "omit" : "cancel"
      });
    }
    return out;
  }

  function isDateWithinGardenSuspensionWindow(date, christmasYear, rule) {
    if (!(date instanceof Date) || !Number.isFinite(date.getTime()) || !rule) return false;
    const startOffsetDays = Number.isFinite(rule?.startOffsetDays) ? Number(rule.startOffsetDays) : 0;
    const durationDays = Number.isFinite(rule?.durationDays) && rule.durationDays > 0 ? Number(rule.durationDays) : 14;
    const christmas = new Date(christmasYear, 11, 25);
    const start = addDays(christmas, startOffsetDays);
    const resume = addDays(start, durationDays);
    return date >= start && date < resume;
  }

  async function getGardenSuspensionRule() {
    if (state.gardenSuspensionRule !== undefined) return state.gardenSuspensionRule;
    let parsed = null;
    try {
      const url = new URL(XMAS_COLLECTIONS_PATH, location.origin).toString();
      const res = await fetch(url, { credentials: "include", cache: "no-cache" });
      if (res.ok) {
        const html = await res.text();
        const doc = new DOMParser().parseFromString(html, "text/html");
        const text = norm(doc.body?.textContent || "");
        parsed = parseGardenSuspensionRule(text);
      }
    } catch (error) {
      console.warn("[HBC PDF] garden suspension lookup failed:", error);
    }
    state.gardenSuspensionRule = parsed;
    return parsed;
  }

  function parseGardenSuspensionRule(text) {
    const src = norm(text);
    if (!src) return null;
    const dayName = "(Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday)";
    const re = new RegExp(
      "garden waste collections are suspended from\\s+" +
      dayName +
      "\\s+(\\d{1,2})\\s+([A-Za-z]+)(?:\\s+(\\d{4}))?\\s*" +
      "(?:,\\s*)?(?:and\\s+)?(?:restart(?:s)?|re-?start(?:s)?|(?:are\\s+)?back to normal|return(?:s)?\\s+to\\s+normal)\\s+on\\s+" +
      dayName +
      "\\s+(\\d{1,2})\\s+([A-Za-z]+)(?:\\s+(\\d{4}))?",
      "i"
    );
    const m = src.match(re);
    if (!m) return null;
    const startDay = Number(m[2]);
    const startMonth = MONTHS[String(m[3] || "").toLowerCase()];
    const startYearRaw = Number(m[4]);
    const endDay = Number(m[6]);
    const endMonth = MONTHS[String(m[7] || "").toLowerCase()];
    const endYearRaw = Number(m[8]);
    if (!Number.isFinite(startDay) || !Number.isFinite(endDay) || startMonth === undefined || endMonth === undefined) {
      return null;
    }
    let startYear = Number.isFinite(startYearRaw) ? startYearRaw : NaN;
    let endYear = Number.isFinite(endYearRaw) ? endYearRaw : NaN;
    if (!Number.isFinite(startYear) || !Number.isFinite(endYear)) {
      const now = new Date();
      let best = null;
      for (let y = now.getFullYear() - 2; y <= now.getFullYear() + 2; y++) {
        const candidateStartYear = Number.isFinite(startYear) ? startYear : y;
        const candidateEndYear = Number.isFinite(endYear)
          ? endYear
          : (endMonth < startMonth ? candidateStartYear + 1 : candidateStartYear);
        const s = new Date(candidateStartYear, startMonth, startDay);
        const e = new Date(candidateEndYear, endMonth, endDay);
        const valid = s.getMonth() === startMonth && s.getDate() === startDay && e.getMonth() === endMonth && e.getDate() === endDay && e > s;
        if (!valid) continue;
        const delta = Math.abs(s.getTime() - now.getTime());
        if (!best || delta < best.delta) best = { startYear: candidateStartYear, endYear: candidateEndYear, delta };
      }
      if (!best) return null;
      startYear = best.startYear;
      endYear = best.endYear;
    }
    const start = new Date(startYear, startMonth, startDay);
    const resume = new Date(endYear, endMonth, endDay);
    if (!Number.isFinite(start.getTime()) || !Number.isFinite(resume.getTime()) || resume <= start) return null;
    const christmas = new Date(start.getFullYear(), 11, 25);
    const startOffsetDays = daysBetween(christmas, start);
    const durationDays = daysBetween(start, resume);
    return {
      startOffsetDays,
      durationDays: durationDays > 0 ? durationDays : 14,
      sourceChristmasYear: start.getFullYear()
    };
  }

  function addDays(date, days) {
    const out = new Date(date.getTime());
    out.setDate(out.getDate() + Number(days || 0));
    return out;
  }

  function daysBetween(a, b) {
    return Math.round((b.getTime() - a.getTime()) / 86400000);
  }

  async function loadIcons(lookup) {
    const rec = await toDataUrl(resolveIconUrl(lookup?.recycling?.image));
    const rub = await toDataUrl(resolveIconUrl(lookup?.rubbish?.image));
    const gar = lookup?.garden
      ? await toDataUrl(resolveIconUrl(lookup.garden.image))
      : null;
    const food = lookup?.food
      ? await toDataUrl(resolveIconUrl(lookup.food.image))
      : null;
    return { recycling: rec, rubbish: rub, garden: gar, food };
  }

  function resolveIconUrl(name) {
    const n = String(name || "").trim();
    if (!n) throw new Error("Missing icon path.");
    if (/^https?:\/\//i.test(n)) return n;
    return BIN_IMAGE_BASE + n;
  }

  async function toDataUrl(url) {
    const r = await fetch(url, { credentials: "omit", cache: "force-cache" });
    if (!r.ok) {
      throw new Error("Failed to fetch icon URL: " + url + " (HTTP " + r.status + ")");
    }
    return blobToDataUrl(await r.blob());
  }

  function buildPdf(jsPDFCtor, c) {
    const doc = new jsPDFCtor({ orientation: "portrait", unit: "mm", format: "a4", compress: true });
    const W = doc.internal.pageSize.getWidth();
    const H = doc.internal.pageSize.getHeight();
    const DESIGN_W = 210;
    const DESIGN_H = 405;
    const col = c.isWeekly
      ? {
          bg: [248, 201, 223],
          sky: [255, 255, 255],
          ink: [0, 0, 0],
          muted: [42, 42, 42],
          line: [0, 0, 0],
          panel: [255, 255, 255],
          month: [0, 0, 0],
          accent: [214, 0, 90],
          accentSoft: [242, 216, 228],
          rec: [214, 0, 90],
          rub: [36, 36, 36],
          gar: [130, 87, 38],
          food: [103, 72, 34]
        }
      : {
          bg: [179, 214, 165],
          sky: [161, 218, 248],
          ink: [0, 0, 0],
          muted: [42, 42, 42],
          line: [0, 0, 0],
          panel: [255, 255, 255],
          month: [0, 0, 0],
          accent: [214, 0, 90],
          accentSoft: [235, 226, 232],
          rec: [34, 166, 71],
          rub: [128, 128, 128],
          gar: [130, 87, 38],
          food: [103, 72, 34]
        };

    const pagePadX = 9.0;
    const gridX = 9.0;
    const baseBandW = 191.5;
    const scale = H / DESIGN_H;
    const stretchX = 1 / scale;
    const offsetX = pagePadX * (1 - scale);
    const sdoc = createScaledDoc(doc, { scaleX: scale, scaleY: scale, offsetX, offsetY: 0 });
    const ydoc = createScaledDoc(doc, { scaleX: 1, scaleY: scale, offsetX: 0, offsetY: 0 });
    const gridW = baseBandW * stretchX;
    const pxToMm = 0.264583;
    const rowH = 18.9;
    const rowGap = 2.15;
    const monthBodyGap = 3.4 + 3 * pxToMm;
    const tileGapX = 1.55 + 7 * pxToMm;
    const titleY = 20.0;
    const subtitleY = 31.0;
    const holidayY = 37.9;
    const holidayW = baseBandW * stretchX;
    const holidayH = 51.4;
    const keyY = 94.8;
    const tableTop = keyY + rowH + rowGap;
    const primaryDay = primaryCollectionDay(c.months, c.isWeekly);
    const holidayRows = buildHolidayRowsFromBoldCore(c.months, c.isWeekly, c.year, primaryDay);
    const subtitle = "Your collection day for " + c.year + " is " + primaryDay.toUpperCase();

    doc.setFillColor(col.bg[0], col.bg[1], col.bg[2]);
    doc.rect(0, 0, W, H, "F");

    sdoc.setFont("helvetica", "bold");
    sdoc.setFontSize(24.5);
    sdoc.setTextColor(col.ink[0], col.ink[1], col.ink[2]);
    sdoc.text(subtitle, pagePadX, titleY);

    sdoc.setFont("helvetica", "normal");
    sdoc.setFontSize(13.8);
    sdoc.setTextColor(col.ink[0], col.ink[1], col.ink[2]);
    sdoc.text("Please use this calendar from the dates below and recycle your previous calendar.", pagePadX, subtitleY);

    drawHolidayPanel(sdoc, {
      x: pagePadX,
      y: holidayY,
      w: holidayW,
      h: holidayH,
      year: c.year,
      primaryDay,
      rows: holidayRows,
      col
    });

    drawKeyRow(sdoc, {
      x: gridX,
      y: keyY,
      monthW: 18.9,
      rowH,
      bodyGap: monthBodyGap,
      gridW,
      items: getKeyItems(c),
      monthLabelSize: 15.5,
      keyItemSize: 12.4,
      col
    });

    const primaryDayIndex = weekdayNameToIndex(primaryDay);
    const maxCollections = 11;
    const monthW = 18.9;
    const monthBodyW = gridW - monthW - monthBodyGap;
    const monthCounts = c.months.map((month) =>
      collectMonthEvents(month, c.isWeekly, c.icons, primaryDayIndex).length
    );
    const needsGlobalShrink = monthCounts.some((count) => {
      if (count <= 1) return false;
      const neededAtBaseGap = count * rowH + (count - 1) * tileGapX;
      return count > maxCollections || neededAtBaseGap > monthBodyW;
    });
    const maxMonthCount = monthCounts.length ? Math.max(...monthCounts) : 0;
    const globalTileW =
      needsGlobalShrink && maxMonthCount > 1
        ? Math.max(0.5, (monthBodyW - (maxMonthCount - 1) * tileGapX) / maxMonthCount)
        : rowH;

    c.months.forEach((month, idx) => {
      drawMonthRow(sdoc, {
        x: gridX,
        y: tableTop + idx * (rowH + rowGap),
        w: gridW,
        h: rowH,
        month,
        isWeekly: c.isWeekly,
        primaryDayIndex,
        bodyGap: monthBodyGap,
        baseGapX: tileGapX,
        maxCollections,
        forceShrinkAll: needsGlobalShrink,
        globalTileW,
        monthLabelSize: 15.5,
        icons: c.icons,
        col
      });
    });
    drawFooterBar(ydoc, c.scheduleCode, c.isWeekly, DESIGN_W, DESIGN_H, scale);
    return doc;
  }

  function createScaledDoc(doc, layout) {
    const sxScale = Number(layout?.scaleX ?? layout?.scale) || 1;
    const syScale = Number(layout?.scaleY ?? layout?.scale) || 1;
    const lineScale = Math.min(sxScale, syScale);
    const ox = Number(layout?.offsetX) || 0;
    const oy = Number(layout?.offsetY) || 0;
    const sx = (x) => ox + Number(x || 0) * sxScale;
    const sy = (y) => oy + Number(y || 0) * syScale;
    const ssx = (v) => Number(v || 0) * sxScale;
    const ssy = (v) => Number(v || 0) * syScale;
    const ssl = (v) => Number(v || 0) * lineScale;

    return {
      setFillColor: (...args) => doc.setFillColor(...args),
      setDrawColor: (...args) => doc.setDrawColor(...args),
      setTextColor: (...args) => doc.setTextColor(...args),
      setFont: (...args) => doc.setFont(...args),
      setLineCap: (...args) => doc.setLineCap(...args),
      setLineJoin: (...args) => doc.setLineJoin(...args),
      setLineWidth: (w) => doc.setLineWidth(ssl(w)),
      setLineDashPattern: (pattern, phase) =>
        doc.setLineDashPattern(
          Array.isArray(pattern) ? pattern.map((v) => ssl(v)) : pattern,
          ssl(phase || 0)
        ),
      setFontSize: (size) => doc.setFontSize(ssy(size)),
      getFontSize: () => doc.getFontSize() / syScale,
      getTextWidth: (text) => doc.getTextWidth(text) / sxScale,
      splitTextToSize: (text, maxWidth) =>
        typeof doc.splitTextToSize === "function"
          ? doc.splitTextToSize(text, ssx(maxWidth))
          : [String(text || "")],
      rect: (x, y, w, h, style) => doc.rect(sx(x), sy(y), ssx(w), ssy(h), style),
      line: (x1, y1, x2, y2) => doc.line(sx(x1), sy(y1), sx(x2), sy(y2)),
      circle: (x, y, r, style) => doc.circle(sx(x), sy(y), ssl(r), style),
      triangle: (x1, y1, x2, y2, x3, y3, style) =>
        doc.triangle(sx(x1), sy(y1), sx(x2), sy(y2), sx(x3), sy(y3), style),
      text: (text, x, y, ...rest) => doc.text(text, sx(x), sy(y), ...rest),
      getImageProperties: (data) => doc.getImageProperties(data),
      addImage: (...args) => {
        const out = args.slice();
        if (out.length >= 6) {
          out[2] = sx(out[2]);
          out[3] = sy(out[3]);
          out[4] = ssx(out[4]);
          out[5] = ssy(out[5]);
        }
        return doc.addImage(...out);
      }
    };
  }

  function drawHolidayPanel(doc, c) {
    doc.setFillColor(c.col.sky[0], c.col.sky[1], c.col.sky[2]);
    doc.setDrawColor(c.col.line[0], c.col.line[1], c.col.line[2]);
    doc.setLineWidth(0.53);
    doc.rect(c.x, c.y, c.w, c.h, "FD");

    doc.setFont("helvetica", "bold");
    doc.setFontSize(17.5);
    doc.setTextColor(c.col.ink[0], c.col.ink[1], c.col.ink[2]);
    doc.text("Christmas and New Year Rubbish & Recycling Collections " + (c.year - 1) + "-" + c.year, c.x + 4.65, c.y + 9.35);

    const rows = Array.isArray(c.rows) ? c.rows : [];
    if (rows.length) {
      doc.setFont("helvetica", "bold");
      doc.setFontSize(12.4);
      doc.text("Normal Collection Day:", c.x + 4.65, c.y + 17.75);
      doc.text("Revised Collection Day:", c.x + 109.4, c.y + 17.75);
      drawHolidayArrow(doc, c.x + 90.3, c.y + 16.45);

      doc.setFont("helvetica", "normal");
      doc.setFontSize(11.7);
      for (let i = 0; i < rows.length; i++) {
        const yy = c.y + 25.3 + i * 7.06;
        doc.text(rows[i].normal, c.x + 4.65, yy);
        drawHolidayArrow(doc, c.x + 90.3, yy - 1.3);
        doc.setFont("helvetica", "normal");
        doc.text(rows[i].revised, c.x + 109.4, yy);
      }
    }

    const footerText = rows.length > 3
      ? ""
      : rows.length
        ? "All other bank holiday collections take place as normal"
        : "No exceptions found.";
    if (footerText) {
      doc.setFont("helvetica", "normal");
      doc.setFontSize(11.7);
      doc.text(footerText, c.x + 4.65, c.y + c.h - 3.9);
    }
    drawHolly(doc, c.x + c.w - 0.35, c.y + c.h - 0.35, 1.3);
  }

  function buildHolidayRowsFromBoldCore(months, isWeekly, year, primaryDay) {
    const core = [];
    for (const month of months || []) {
      if (isWeekly) core.push(...(month.dates || []));
      else {
        core.push(...(month.recycling || []));
        core.push(...(month.rubbish || []));
      }
    }
    const allCore = dedupeSortItems(core);
    const start = new Date(year - 1, 11, 20);
    const end = new Date(year, 0, 31);
    const windowCore = dedupeSortItems(
      core.filter((it) => it && it.date instanceof Date && it.date >= start && it.date <= end)
    );
    const revisedAll = dedupeSortDates(
      windowCore.filter((it) => !!it.bold).map((it) => new Date(it.date))
    );
    if (!revisedAll.length) return [];

    const revisedShown = revisedAll.slice(0, revisedAll.length >= 3 ? 3 : 2);
    const rows = revisedShown.map((revisedDate) => ({
      normal: formatLongDate(nearestWeekdayToDate(primaryDay, revisedDate)),
      revised: formatLongDate(revisedDate)
    }));

    const latestBold = revisedAll[revisedAll.length - 1];
    const resumeDate = allCore.find((it) => !it.bold && it.date > latestBold)?.date || null;
    if (resumeDate) {
      rows.push({ normal: formatLongDate(resumeDate), revised: "Normal Collections Resume" });
    }
    return rows;
  }

  function nearestWeekdayToDate(weekdayName, nearDate) {
    const names = ["sunday", "monday", "tuesday", "wednesday", "thursday", "friday", "saturday"];
    const target = names.indexOf(String(weekdayName || "").toLowerCase());
    if (target < 0) return new Date(nearDate);
    const d = new Date(nearDate);
    while (d.getDay() !== target) d.setDate(d.getDate() - 1);
    return d;
  }

  function formatLongDate(d) {
    const wd = d.toLocaleDateString("en-GB", { weekday: "long" });
    const mo = d.toLocaleDateString("en-GB", { month: "long" });
    return wd + " " + ordinalDay(d.getDate()) + " " + mo + " " + d.getFullYear();
  }

  function drawHolly(doc, x, y, s) {
    const w = 9.2 * s;
    const h = 10.6 * s;
    const berryX = 3.7 * s;
    const berryY = 4.2 * s;
    const xx = x - berryX;
    const yy = y - berryY;
    doc.addImage(HOLLY_DATA_URL, "PNG", xx, yy, w, h, undefined, "FAST");
  }

  function drawHolidayArrow(doc, x, y) {
    doc.setDrawColor(0, 0, 0);
    doc.setFillColor(0, 0, 0);
    doc.setLineWidth(0.7);
    doc.setLineCap("round");
    doc.line(x, y, x + 2.0, y);
    doc.triangle(x + 2.0, y - 1.15, x + 5.0, y, x + 2.0, y + 1.15, "F");
    doc.setLineCap("butt");
  }

  function getKeyItems(c) {
    const items = [
      { label1: "Rubbish", icon: c.icons.rubbish, kind: "rubbish" },
      { label1: "Recycling", icon: c.icons.recycling, kind: "recycling" }
    ];
    if (c.hasGarden) items.push({ label1: "Garden waste", icon: c.icons.garden, kind: "garden" });
    if (c.hasFood) items.push({ label1: "Food waste", icon: c.icons.food, kind: "food" });
    return items;
  }

  function drawKeyRow(doc, c) {
    doc.setFillColor(c.col.month[0], c.col.month[1], c.col.month[2]);
    doc.rect(c.x, c.y, c.monthW, c.rowH, "F");
    doc.setFont("helvetica", "bold");
    doc.setFontSize(c.monthLabelSize || 15.5);
    doc.setTextColor(255, 255, 255);
    doc.text("Key", c.x + c.monthW / 2, c.y + 11.65, { align: "center" });

    const bodyLeft = c.x + c.monthW + c.bodyGap;
    const bodyMaxW = c.gridW - c.monthW - c.bodyGap;
    const itemGap = 6.6;
    const sidePad = 4.8;
    const baseSize = c.keyItemSize || 12.4;
    const items = Array.isArray(c.items) ? c.items : [];

    doc.setFont("helvetica", "normal");
    doc.setFontSize(baseSize);
    const layouts = items.map((it) => {
      const iconW = 9.0;
      const iconH = iconW * 1.06;
      const textGap = 1.9;
      const label1 = String(it?.label1 || "");
      const textW = Math.max(
        8.8,
        doc.getTextWidth(label1)
      );
      const itemW = Math.max(22, iconW + textGap + textW + 1.2);
      return { itemW, iconW, iconH, textGap };
    });

    const totalItemsW = layouts.reduce((sum, l) => sum + l.itemW, 0);
    let gap = itemGap;
    let pad = sidePad;
    let bodyW = totalItemsW + gap * Math.max(0, layouts.length - 1) + pad * 2;
    if (bodyW > bodyMaxW && layouts.length) {
      const minGap = 2.2;
      const minPad = 2.2;
      if (layouts.length > 1) {
        const maxGap = (bodyMaxW - totalItemsW - pad * 2) / (layouts.length - 1);
        gap = Math.max(minGap, Math.min(gap, maxGap));
      }
      const maxPad = (bodyMaxW - totalItemsW - gap * Math.max(0, layouts.length - 1)) / 2;
      pad = Math.max(minPad, Math.min(pad, maxPad));
      bodyW = totalItemsW + gap * Math.max(0, layouts.length - 1) + pad * 2;
    }
    const bodyX = bodyLeft;

    doc.setFillColor(255, 255, 255);
    doc.setDrawColor(c.col.line[0], c.col.line[1], c.col.line[2]);
    doc.setLineWidth(0.4);
    doc.rect(bodyX, c.y, bodyW, c.rowH, "FD");

    const itemTop = c.y + 0.35;
    const itemBottom = c.y + c.rowH - 0.45;
    const itemMidY = (itemTop + itemBottom) / 2;

    let ix = bodyX + pad;
    for (let i = 0; i < items.length; i++) {
      const it = items[i];
      if (!it) continue;
      const layout = layouts[i] || { itemW: 22, iconW: 9.0, iconH: 9.54, textGap: 1.9 };
      const itemW = layout.itemW;
      const iconW = layout.iconW;
      const iconH = layout.iconH;
      const iconY = itemMidY - iconH / 2;
      const iconX = ix;
      drawIcon(doc, it.icon, iconX, iconY, iconW, iconH);
      const textX = iconX + iconW + layout.textGap;
      const textW = Math.max(7.6, itemW - iconW - layout.textGap);
      let fz = c.keyItemSize || 12.4;
      let lines = wrapTextLines(doc, it.label1 || "", textW, 99, fz);
      while (lines.length > 2 && fz > 9.2) {
        fz -= 0.4;
        lines = wrapTextLines(doc, it.label1 || "", textW, 99, fz);
      }
      if (lines.length > 2) lines = lines.slice(0, 2);
      doc.setFont("helvetica", "normal");
      doc.setFontSize(fz);
      doc.setTextColor(0, 0, 0);
      const lineCount = Math.max(1, lines.length);
      const lineStep = Math.max(3.95, Math.min(4.65, fz * 0.35));
      const blockH = lineStep * (lineCount - 1);
      const baselineNudge = Math.max(1.2, lineStep * 0.34);
      const firstY = itemMidY - blockH / 2 + baselineNudge;
      for (let li = 0; li < lineCount; li++) {
        doc.text(lines[li], textX, firstY + li * lineStep);
      }
      ix += itemW + gap;
    }
  }

  function drawFooterBar(doc, scheduleCode, isWeekly, W, H, metricScale) {
    const bh = 8.8;
    const x = 0;
    const y = H - bh;
    const pxToMm = 0.264583;
    const footerShift = 10 * pxToMm;
    doc.setFillColor(0, 0, 0);
    doc.rect(x, y, W, bh, "F");
    doc.setTextColor(255, 255, 255);
    doc.setFont("helvetica", "bold");
    const fortBadgeW = 33.8;
    const fortLabel = getFortLabel(scheduleCode);
    doc.setFontSize(14);
    const widthScale = Number(metricScale) > 0 ? Number(metricScale) : 1;
    const fortLabelW = fortLabel ? doc.getTextWidth(fortLabel) / widthScale : 0;
    const fortPad = fortLabel ? Math.max(1.5, (fortBadgeW - fortLabelW) / 2) : 1.5;
    const refFortLabelW = doc.getTextWidth("FORT 1") / widthScale;
    const refFortPad = Math.max(1.5, (fortBadgeW - refFortLabelW) / 2);
    const footerTextX = isWeekly
      ? Math.max(1.5, refFortPad - footerShift)
      : Math.max(1.5, fortPad - footerShift);

    doc.setFontSize(8.9);
    doc.text("Generate your own collection calendar at github.com/AV1917/restore-hastings-bin-calendar", x + footerTextX, y + bh / 2 - 0.26, { baseline: "middle" });
    if (!isWeekly) {
      const renderedFortLabel = getFortLabel(scheduleCode);
      if (renderedFortLabel) {
        doc.setFontSize(14);
        doc.text(renderedFortLabel, W - fortBadgeW / 2 + footerShift * 2, y + 6.1, { align: "center" });
      }
    }
  }

  function normaliseDateItems(values) {
    if (!Array.isArray(values)) throw new Error("Invalid date list.");
    const out = [];
    for (const raw of values) {
      const item = raw && typeof raw === "object" && !(raw instanceof Date) ? raw : null;
      const source = item ? item.date : raw;
      if (source === undefined || source === null) throw new Error("Invalid date item.");
      let date;
      if (source instanceof Date) date = new Date(source.getTime());
      else {
        const m = String(source).match(/\/Date\((\d+)(?:[+-]\d+)?\)\//);
        date = m ? new Date(Number(m[1])) : new Date(source);
      }
      if (!Number.isFinite(date.getTime())) throw new Error("Invalid date item.");
      out.push({ date, bold: !!item?.bold, estimated: !!item?.estimated });
    }
    return dedupeSortItems(out);
  }

  function getFortLabel(scheduleCode) {
    const m = String(scheduleCode || "").match(/fort(?:nightly)?\s*([0-9]+)/i) || String(scheduleCode || "").match(/fort([0-9]+)/i);
    return m ? "FORT " + m[1] : "";
  }

  function drawMonthRow(doc, c) {
    const monthW = 18.9;
    const bodyGap = Number.isFinite(Number(c.bodyGap)) ? Number(c.bodyGap) : 3.4;
    const events = collectMonthEvents(c.month, c.isWeekly, c.icons, c.primaryDayIndex);

    doc.setFillColor(c.col.month[0], c.col.month[1], c.col.month[2]);
    doc.rect(c.x, c.y, monthW, c.h, "F");
    doc.setTextColor(255, 255, 255);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(c.monthLabelSize || 15.5);
    doc.text(monthShort(c.month.idx), c.x + monthW / 2, c.y + 11.65, { align: "center" });

    const bodyX = c.x + monthW + bodyGap;
    const bodyW = c.w - monthW - bodyGap;
    if (!events.length) {
      doc.setFont("helvetica", "normal");
      doc.setFontSize(5.8);
      doc.setTextColor(c.col.muted[0], c.col.muted[1], c.col.muted[2]);
      doc.text("No dates listed", bodyX + 1.2, c.y + c.h / 2 + 1);
      return;
    }

    const maxCollections = Number.isFinite(Number(c.maxCollections)) ? Number(c.maxCollections) : 11;
    const visible = events.slice();
    const tileH = c.h;
    const squareW = c.h;
    const baseGapX = Number.isFinite(Number(c.baseGapX)) ? Number(c.baseGapX) : 1.55;
    const tileGapX = baseGapX;
    const count = visible.length;
    let shrinkMode = false;
    let tileW = squareW;

    if (c.forceShrinkAll) {
      shrinkMode = true;
      if (Number.isFinite(Number(c.globalTileW)) && Number(c.globalTileW) > 0) {
        tileW = Math.min(squareW, Number(c.globalTileW));
      } else if (count > 1) {
        tileW = (bodyW - (count - 1) * baseGapX) / count;
      }
    } else if (count > 1) {
      const neededAtBaseGap = count * squareW + (count - 1) * baseGapX;
      if (count > maxCollections || neededAtBaseGap > bodyW) {
        shrinkMode = true;
        tileW = (bodyW - (count - 1) * baseGapX) / count;
      }
    }
    tileW = Math.max(0.5, tileW);

    for (let i = 0; i < visible.length; i++) {
      const x = bodyX + i * (tileW + tileGapX);
      const y = c.y;
      drawCollectionTile(doc, {
        x,
        y,
        w: tileW,
        h: tileH,
        event: visible[i],
        shrinkMode,
        col: c.col
      });
    }
  }

  function monthShort(idx) {
    return ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"][Number(idx) || 0] || "Jan";
  }

  function collectMonthEvents(month, isWeekly, icons, primaryDayIndex) {
    const byDate = new Map();
    function ensure(date) {
      const k = date.getTime();
      if (!byDate.has(k)) byDate.set(k, { date, bold: false, bins: [], hasCore: false });
      return byDate.get(k);
    }
    function add(dateItem, bin, isCore) {
      if (!dateItem || !dateItem.date) return;
      const entry = ensure(dateItem.date);
      entry.bold = entry.bold || !!dateItem.bold;
      entry.hasCore = entry.hasCore || !!isCore;
      const isCancelled = bin.kind === "garden" && !!dateItem.cancelled;
      const existing = entry.bins.find((b) => b.kind === bin.kind);
      if (!existing) {
        entry.bins.push(Object.assign({}, bin, { cancelled: isCancelled }));
      } else if (isCancelled) {
        existing.cancelled = true;
      }
    }

    const recBin = { kind: "recycling", icon: icons.recycling };
    const rubBin = { kind: "rubbish", icon: icons.rubbish };
    const garBin = { kind: "garden", icon: icons.garden };
    const foodBin = { kind: "food", icon: icons.food };

    if (isWeekly) {
      for (const d of month.dates || []) {
        add(d, recBin, true);
        add(d, rubBin, true);
      }
    } else {
      for (const d of month.recycling || []) add(d, recBin, true);
      for (const d of month.rubbish || []) add(d, rubBin, true);
    }

    for (const d of month.garden || []) add(d, garBin, false);
    for (const d of month.food || []) add(d, foodBin, false);

    return Array.from(byDate.values())
      .map((entry) => ({
        date: entry.date,
        bold: entry.bold,
        bins: entry.bins,
        exception:
          entry.hasCore &&
          Number.isInteger(primaryDayIndex) &&
          primaryDayIndex >= 0 &&
          entry.date.getDay() !== primaryDayIndex
      }))
      .sort((a, b) => a.date - b.date);
  }

  function drawCollectionTile(doc, c) {
    const isException = !!c.event.exception;
    const hasCancelled = (c.event.bins || []).some((bin) => !!bin?.cancelled);
    const borderColour = hasCancelled ? [196, 0, 0] : c.col.line;
    const borderWidth = hasCancelled ? 0.53 : 0.54;
    doc.setFillColor(255, 255, 255);
    doc.setDrawColor(borderColour[0], borderColour[1], borderColour[2]);
    doc.setLineWidth(borderWidth);
    doc.rect(c.x, c.y, c.w, c.h, "F");
    if (!isException && !hasCancelled) {
      doc.setLineCap("round");
      doc.setLineJoin("round");
      doc.setLineDashPattern([0.01, 1.05], 0);
    } else {
      doc.setLineDashPattern([], 0);
      doc.setLineCap("butt");
      doc.setLineJoin("miter");
    }
    doc.rect(c.x, c.y, c.w, c.h, "S");
    doc.setLineDashPattern([], 0);
    doc.setLineCap("butt");
    doc.setLineJoin("miter");

    const bins = (c.event.bins || [])
      .filter((bin) => isKnownBinKind(bin?.kind))
      .slice()
      .sort((a, b) => {
        const pa = getBinPriority(a);
        const pb = getBinPriority(b);
        if (pa !== pb) return pa - pb;
        return String(a?.kind || "").localeCompare(String(b?.kind || ""));
      })
      .slice(0, 4);
    doc.setFont("helvetica", "bold");
    const splitDate = !!c.shrinkMode;
    doc.setFontSize(10.2);
    doc.setTextColor(c.col.ink[0], c.col.ink[1], c.col.ink[2]);
    let centeredLayout = null;
    let dateBottomY = c.y + 6.0;
    if (splitDate) {
      const dateBlockH = 8.2;
      const dateLineGap = 4.15;
      const dateSplitBaselineOffset = 3.05;
      const contentGapY = bins.length ? 0.6 : 0;
      const innerPadY = 0.6;
      let frameW = 0;
      let step = 0;
      let overlap = false;
      let normalGap = 0.85;
      if (bins.length > 0) {
        const padX = 1.6;
        const availW = Math.max(2.4, c.w - padX * 2);
        const naturalFrameW = 7.2;
        const sideBySideW = naturalFrameW * bins.length + normalGap * Math.max(0, bins.length - 1);
        frameW = naturalFrameW;
        step = frameW + normalGap;
        if (sideBySideW > availW && bins.length > 1) {
          overlap = true;
          step = bins.length > 1 ? (availW - frameW) / (bins.length - 1) : frameW;
          step = Math.max(frameW * 0.25, Math.min(step, frameW + normalGap));
        }
        frameW = Math.max(2.2, Math.min(frameW, naturalFrameW));
      }
      let frameH = bins.length > 0 ? Math.max(2.5, frameW * 1.1) : 0;
      const minContentH = Math.max(2.2, c.h - innerPadY * 2);
      if (bins.length > 0) {
        const maxFrameH = Math.max(2.2, minContentH - dateBlockH - contentGapY);
        frameH = Math.min(frameH, maxFrameH);
      }
      const totalContentH = dateBlockH + contentGapY + frameH;
      const contentTop = c.y + (c.h - totalContentH) / 2;
      const d = c.event.date;
      const line1 = weekdayShort(d.getDay());
      const line2 = ordinalDay(d.getDate());
      const line1Y = contentTop + dateSplitBaselineOffset;
      const line2Y = line1Y + dateLineGap;
      doc.text(line1, c.x + c.w / 2, line1Y, { align: "center" });
      doc.text(line2, c.x + c.w / 2, line2Y, { align: "center" });
      dateBottomY = contentTop + dateBlockH;
      centeredLayout = { frameW, frameH, step, overlap, normalGap, zoneTop: dateBottomY + contentGapY };
    } else {
      doc.text(fmtDate(c.event.date), c.x + c.w / 2, c.y + 5.2, { align: "center" });
    }
    if (bins.length > 0) {
      let frameW;
      let frameH;
      let step;
      let overlap;
      let normalGap;
      let zoneTop;
      if (splitDate && centeredLayout) {
        frameW = centeredLayout.frameW;
        frameH = centeredLayout.frameH;
        step = centeredLayout.step;
        overlap = centeredLayout.overlap;
        normalGap = centeredLayout.normalGap;
        zoneTop = centeredLayout.zoneTop;
      } else {
        zoneTop = dateBottomY + 0.35;
        const zoneBottom = c.y + c.h - 0.75;
        const zoneH = Math.max(2.2, zoneBottom - zoneTop);
        const padX = 1.6;
        const availW = Math.max(2.4, c.w - padX * 2);
        normalGap = 0.85;
        const naturalFrameW = 7.2;
        const sideBySideW = naturalFrameW * bins.length + normalGap * Math.max(0, bins.length - 1);
        frameW = naturalFrameW;
        step = frameW + normalGap;
        overlap = false;
        if (sideBySideW > availW && bins.length > 1) {
          overlap = true;
          step = bins.length > 1 ? (availW - frameW) / (bins.length - 1) : frameW;
          step = Math.max(frameW * 0.25, Math.min(step, frameW + normalGap));
        }
        frameW = Math.max(2.2, Math.min(frameW, naturalFrameW));
        frameH = Math.max(2.5, Math.min(zoneH, frameW * 1.1));
      }
      const totalW = overlap ? (frameW + step * (bins.length - 1)) : (frameW * bins.length + normalGap * (bins.length - 1));
      const startX = c.x + (c.w - totalW) / 2;
      const frameY = splitDate ? zoneTop : zoneTop + ((c.y + c.h - 0.75) - zoneTop - frameH) / 2;
      const frames = [];
      for (let i = 0; i < bins.length; i++) {
        frames.push({
          bin: bins[i],
          x: startX + (overlap ? i * step : i * (frameW + normalGap)),
          y: frameY,
          w: frameW,
          h: frameH
        });
      }
      if (overlap) {
        for (let i = frames.length - 1; i >= 0; i--) {
          const f = frames[i];
          drawIcon(doc, f.bin.icon, f.x, f.y, f.w, f.h);
        }
      } else {
        for (const f of frames) {
          drawIcon(doc, f.bin.icon, f.x, f.y, f.w, f.h);
        }
      }
    }
    if (hasCancelled) {
      drawCancelledMark(doc, c.x, c.y, c.w, c.h);
      doc.setDrawColor(borderColour[0], borderColour[1], borderColour[2]);
      doc.setLineWidth(borderWidth);
      doc.setLineCap("butt");
      doc.setLineJoin("miter");
      doc.setLineDashPattern([], 0);
      doc.rect(c.x, c.y, c.w, c.h, "S");
    }
  }

  function drawCancelledMark(doc, x, y, w, h) {
    const stroke = 0.6;
    const inset = Math.max(0.18, stroke * 0.7);
    doc.setDrawColor(196, 0, 0);
    doc.setLineWidth(stroke);
    doc.setLineCap("round");
    doc.setLineJoin("round");
    doc.setLineDashPattern([], 0);
    doc.line(x + inset, y + inset, x + w - inset, y + h - inset);
    doc.line(x + w - inset, y + inset, x + inset, y + h - inset);
  }

  function isKnownBinKind(kind) {
    return kind === "rubbish" || kind === "recycling" || kind === "garden" || kind === "food";
  }

  function getBinPriority(bin) {
    const kind = String(bin?.kind || "");
    if (kind === "rubbish") return 0;
    if (kind === "recycling") return 1;
    if (kind === "garden") return 2;
    if (kind === "food") return 3;
  }

  function primaryCollectionDay(months, isWeekly) {
    const items = [];
    for (const month of months) {
      if (isWeekly) items.push(...(month.dates || []));
      else {
        items.push(...(month.recycling || []));
        items.push(...(month.rubbish || []));
      }
    }
    if (!items.length) {
      throw new Error("No core collection dates found to determine the primary collection day.");
    }
    items.sort((a, b) => a.date - b.date);
    return items[0].date.toLocaleDateString("en-GB", { weekday: "long" });
  }

  function drawIcon(doc, dataUrl, x, y, w, h) {
    const src = String(dataUrl || "").trim();
    if (!src) throw new Error("Missing icon.");
    const props = doc.getImageProperties(src);
    const iw = Number(props?.width);
    const ih = Number(props?.height);
    if (!(iw > 0 && ih > 0)) throw new Error("Invalid icon.");
    const scale = Math.min(w / iw, h / ih);
    const dw = iw * scale;
    const dh = ih * scale;
    const dx = x + (w - dw) / 2;
    const dy = y + (h - dh) / 2;
    doc.addImage(src, "PNG", dx, dy, dw, dh, undefined, "FAST");
  }

  function fmtDate(d) {
    return weekdayShort(d.getDay()) + " " + ordinalDay(d.getDate());
  }

  function weekdayShort(day) {
    return ["Sun", "Mon", "Tue", "Wed", "Thur", "Fri", "Sat"][Number(day) || 0];
  }

  function weekdayNameToIndex(name) {
    const n = String(name || "").toLowerCase();
    if (n === "sunday") return 0;
    if (n === "monday") return 1;
    if (n === "tuesday") return 2;
    if (n === "wednesday") return 3;
    if (n === "thursday") return 4;
    if (n === "friday") return 5;
    if (n === "saturday") return 6;
    return -1;
  }

  function ordinalDay(n) {
    const x = Number(n);
    if (x % 100 >= 11 && x % 100 <= 13) return x + "th";
    if (x % 10 === 1) return x + "st";
    if (x % 10 === 2) return x + "nd";
    if (x % 10 === 3) return x + "rd";
    return x + "th";
  }

  function parseDate(s) {
    const m = String(s || "").match(
      /^(Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday)\s+(\d{1,2})\s+([A-Za-z]+)\s+(\d{4})$/i
    );
    if (!m) return null;
    const day = Number(m[2]), month = MONTHS[m[3].toLowerCase()], year = Number(m[4]);
    if (!Number.isFinite(day) || month === undefined || !Number.isFinite(year)) return null;
    const d = new Date(year, month, day);
    if (d.getFullYear() !== year || d.getMonth() !== month || d.getDate() !== day) return null;
    return d;
  }

  function norm(v) {
    return String(v || "").replace(/\s+/g, " ").trim();
  }

  function monthKey(d) {
    return d.getFullYear() + "-" + String(d.getMonth() + 1).padStart(2, "0");
  }

  function monthLabel(d) {
    return d.toLocaleDateString("en-GB", { month: "long", year: "numeric" });
  }

  function monthName(i) {
    return new Date(2024, i, 1).toLocaleDateString("en-GB", { month: "long" });
  }

  function dedupeSortDates(arr) {
    const m = new Map();
    for (const d of arr) m.set(d.getTime(), d);
    return Array.from(m.values()).sort((a, b) => a - b);
  }

  function dedupeSortItems(arr) {
    const m = new Map();
    for (const it of arr) {
      const k = it.date.getTime();
      if (!m.has(k)) m.set(k, { date: it.date, bold: !!it.bold, estimated: !!it.estimated });
      else {
        const ex = m.get(k);
        ex.bold = ex.bold || !!it.bold;
        ex.estimated = ex.estimated && !!it.estimated;
      }
    }
    return Array.from(m.values()).sort((a, b) => a.date - b.date);
  }

  function wrapTextLines(doc, text, maxWidth, maxLines, fontSize) {
    const src = String(text || "").trim();
    if (!src) return [""];
    const oldSize = doc.getFontSize();
    if (Number.isFinite(fontSize) && fontSize > 0) doc.setFontSize(fontSize);
    let lines;
    if (typeof doc.splitTextToSize === "function") lines = doc.splitTextToSize(src, maxWidth);
    else lines = [src];
    lines = (Array.isArray(lines) ? lines : [String(lines)]).map((v) => String(v || ""));
    if (Number.isFinite(maxLines) && maxLines > 0 && lines.length > maxLines) {
      lines = lines.slice(0, maxLines);
    }
    if (Number.isFinite(oldSize)) doc.setFontSize(oldSize);
    return lines;
  }

  async function getJsPdfCtor() {
    let ctor = findJsPdfCtor();
    if (ctor) return ctor;
    const loadErrors = [];
    for (const src of JSPDF_SRC) {
      try {
        await injectScript(src);
      } catch (error) {
        loadErrors.push("Failed to load jsPDF source " + src + ": " + (error && error.message ? error.message : String(error)));
        continue;
      }
      ctor = findJsPdfCtor();
      if (ctor) return ctor;
      loadErrors.push("jsPDF source loaded but constructor was unavailable: " + src);
    }
    throw new Error("jsPDF is not available. " + loadErrors.join(" | "));
  }

  function findJsPdfCtor() {
    const jspdfNs = typeof window === "object" && window ? window.jspdf : undefined;
    if (jspdfNs && typeof jspdfNs.jsPDF === "function") return jspdfNs.jsPDF;
    return null;
  }

  function injectScript(src) {
    return new Promise((resolve, reject) => {
      const id = "hbc-jspdf-" + src.replace(/[^a-z0-9_-]/gi, "_");
      const old = document.getElementById(id);
      if (old && old.dataset.loaded === "1") return resolve();
      if (old) {
        old.addEventListener("load", resolve, { once: true });
        old.addEventListener("error", () => reject(new Error("load failed")), { once: true });
        return;
      }
      const s = document.createElement("script");
      s.id = id;
      s.src = src;
      s.async = true;
      s.crossOrigin = "anonymous";
      s.addEventListener("load", () => {
        s.dataset.loaded = "1";
        resolve();
      });
      s.addEventListener("error", () => reject(new Error("load failed")));
      (document.head || document.documentElement || document.body).appendChild(s);
    });
  }

  function blobToDataUrl(blob) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result);
      reader.onerror = () => reject(reader.error);
      reader.readAsDataURL(blob);
    });
  }

  const JSPDF_SRC = [
    "https://cdn.jsdelivr.net/npm/jspdf@2.5.1/dist/jspdf.umd.min.js",
    "https://unpkg.com/jspdf@2.5.1/dist/jspdf.umd.min.js"
  ];
})();